#include <vector>
#include <algorithm>
#include <cmath>
#include <limits>

long long solve(std::vector<long long> nums) {
    if (nums.empty()) {
        return 0;
    }

    // 1. Find the maximum value M and determine the set S of unique values
    long long max_val_ll = 0;
    for (long long x : nums) {
        if (x > max_val_ll) {
            max_val_ll = x;
        }
    }

    // M is at most 10^5, safe to cast to int for array indexing
    int M = (int)max_val_ll;

    // present[i] is true if i is in the original array nums
    // Size M+1 for 1-based indexing up to M
    std::vector<bool> present(M + 1, false);
    for (long long x : nums) {
        if (x >= 1 && x <= M) {
            present[(int)x] = true;
        }
    }

    // 2. Pre-calculate min_s[k]: the smallest divisor of k present in S
    // Initialize to M + 1, representing "not found" or infinity relative to M
    std::vector<int> min_s(M + 1, M + 1);

    // Sieve-like approach: iterate through potential divisors y in increasing order
    for (int y = 1; y <= M; ++y) {
        if (present[y]) {
            // y is in S. It is a divisor for all its multiples k.
            for (int k = y; k <= M; k += y) {
                // Since we iterate y in increasing order, the first time we reach k 
                // via division, y is the smallest divisor in S found so far.
                // We use min() for robustness, although strictly speaking, it should be the first time.
                min_s[k] = std::min(min_s[k], y);
            }
        }
    }

    // 3. Calculate the final sum
    long long total_sum = 0;
    for (long long x_ll : nums) {
        int x = (int)x_ll;

        // The minimum reachable value for x is min_s[x]
        int min_reachable_value = min_s[x];

        // Handle the unlikely case where min_s[x] remains M+1 (shouldn't happen if x >= 1 and x is in S)
        // If x is present in S, min_s[x] must be <= x, and since x is in S, min_s[x] <= x is guaranteed.
        if (min_reachable_value > M) {
             // This path implies an issue, but if x is in nums, x must be in S, so min_s[x] = x.
             total_sum += x_ll;
        } else {
             total_sum += min_reachable_value;
        }
    }

    return total_sum;
}

