long long solve(std::vector<long long> nums) {
    if (nums.empty()) {
        return 0;
    }

    // Constraints: 1 <= nums[i] <= 10^5
    const int MAX_VAL = 100000;

    // 1. Determine the maximum value and identify present numbers
    int M = 0;
    for (long long x : nums) {
        if (x > M) {
            M = (int)x;
        }
    }

    // present[i] is true if i is an initial value in nums
    std::vector<bool> present(M + 1, false);
    for (long long x : nums) {
        present[(int)x] = true;
    }

    // results[x] will store the minimum value y in nums such that y divides x.
    // Initialize results[x] = x.
    std::vector<int> results(M + 1);
    for (int i = 1; i <= M; ++i) {
        results[i] = i;
    }

    // 2. Sieve-like process to find the smallest divisor present in nums for all x in nums.
    // Iterate through potential divisors y in increasing order.
    for (int y = 1; y <= M; ++y) {
        if (!present[y]) {
            // y must be an initial value to be used as a replacement element
            continue;
        }

        // y is a valid divisor source. Check its multiples x > y.
        // We start from 2*y because y|y, and results[y] is correctly initialized to y.
        for (int x = 2 * y; x <= M; x += y) {
            if (present[x]) {
                // x is an initial value, and y divides x.
                // Since we iterate y in increasing order, y is guaranteed to be the smallest
                // divisor found so far for x that is present in nums.
                results[x] = y;
            }
        }
    }

    // 3. Calculate the final minimum sum
    long long min_sum = 0;
    for (long long x : nums) {
        // The minimum reachable value for x is stored in results[x]
        min_sum += results[(int)x];
    }

    return min_sum;
}

