    if (nums.empty()) {
        return 0;
    }

    // Constraints state nums[i] <= 10^5.
    const int MAX_VAL = 100000;

    // 1. Find V_set: unique values present in nums.
    std::set<int> v_set;
    for (long long x : nums) {
        // Safely cast assuming inputs adhere to constraints 1 <= nums[i] <= 10^5
        v_set.insert((int)x);
