    // Convert set to sorted vector for controlled iteration (required for the sieve approach)
    std::vector<int> sorted_v_set(v_set.begin(), v_set.end());

    // 2. Preprocessing: MinDivisor[x] stores the smallest d in V_set that divides x.
    // Initialize with a value larger than MAX_VAL.
    std::vector<int> min_divisor(MAX_VAL + 1, MAX_VAL + 1);

    // 3. Sieve-like computation: O(M log M) complexity where M = MAX_VAL.
    // Iterate over d in increasing order (d is guaranteed to be in V_set)
    for (int d : sorted_v_set) {
        // Iterate over all multiples x of d up to MAX_VAL
        for (int x = d; x <= MAX_VAL; x += d) {
            // Since we iterate d in increasing order, d is the minimum divisor in V_set found so far for x.
            // We update min_divisor[x] to d.
            min_divisor[x] = d;
        }
    }

    // 4. Calculate the final minimum sum.
    long long total_sum = 0;
    for (long long x : nums) {
        int val_x = (int)x;

        // Add the minimum achievable value for this element to the sum.
        total_sum += min_divisor[val_x];
    }

    return total_sum;
}

