#include <cmath>
#include <algorithm>
#include <set>

long long solve(std::vector<long long> nums) {
    if (nums.empty()) {
        return 0;
    }

    // Constraints state nums[i] <= 10^5.
    const int MAX_VAL = 100000;

    // 1. Determine which values are present in the initial array using a boolean array for O(1) lookup.
    std::vector<bool> is_unique(MAX_VAL + 1, false);
    for (long long x : nums) {
        if (x >= 1 && x <= MAX_VAL) {
            is_unique[(int)x] = true;
        }
    }

    long long total_min_sum = 0;

    // 2. For each element n_i, find the smallest divisor v present in the initial set.
    for (long long n_i : nums) {
        long long v_min = n_i; // Initialize with n_i, which is always a valid divisor present initially.

        if (n_i == 1) {
            // If n_i is 1, it cannot be reduced further. v_min remains 1.
            total_min_sum += 1;
            continue;
        }

        // Iterate up to sqrt(n_i) to find all divisor pairs (d, n_i/d)
        long long limit = static_cast<long long>(std::sqrt(n_i));

        for (long long d = 1; d <= limit; ++d) {
            if (n_i % d == 0) {

                // Candidate 1: d
                if (d <= MAX_VAL && is_unique[(int)d]) {
                    v_min = std::min(v_min, d);
                }

                // Candidate 2: d' = n_i / d
                long long d_prime = n_i / d;
                if (d_prime <= MAX_VAL && is_unique[(int)d_prime]) {
                    v_min = std::min(v_min, d_prime);
                }
            }
        }

        total_min_sum += v_min;
    }

    return total_min_sum;
}

